const { iso, design, countryName, cloudinaryUrl } = $input.first().json.body;
if (!iso || !design || !cloudinaryUrl) throw new Error('Payload WF-B incomplet');
const designLabels = { D1: 'Slogan', D2: 'Emblème', D3: 'Fantaisie', D4: 'Basic' };
const productTitle = `${countryName} ${designLabels[design]} Fan-Made — Football 2026`;
return [{ json: { iso, design, countryName, cloudinaryUrl, productTitle } }];

const { token, id } = $input.first().json.query;
const expected = $hmac(id, $env.N8N_SECRET);
if (token !== expected) throw new Error('Token invalide');
return [{ json: { printfulProductId: parseInt(id) } }];
